//! GLM-OCR (`glm_ocr_vision`) Vision Transformer encoder.
//!
//! Faithful CPU/f32 port of the GLM-OCR / GLM-4.1V slim vision tower. This is a
//! sibling of `model_qwen2vl_vit.rs` (same Qwen2-VL ViT lineage: Conv3d patch
//! embed, 2D-RoPE, RMSNorm, SwiGLU) but with the GLM-OCR-specific differences,
//! verified against the `zai-org/GLM-OCR` safetensors header (2026-05-24):
//!
//!   vs. Qwen2.5-VL ViT (`model_qwen2vl_vit.rs`):
//!     + patch_embed Conv3d HAS a bias
//!     + per-head q_norm / k_norm RMSNorm ([head_dim]) applied before RoPE
//!     + post_layernorm (final RMSNorm) after the blocks
//!     + spatial merge is a Conv2d `downsample` (2×2, stride 2) -- NOT a reshape
//!     + merger is GLM-style: proj(Linear) → LayerNorm → GELU → SwiGLU(gate*up)→down
//!     - NO window attention (all blocks are full attention)
//!     - NO post_conv_layernorm and NO learned position embedding (this slim
//!       `glm_ocr_vision` variant relies purely on 2D-RoPE)
//!
//! Output: `[n_merged_tokens, out_hidden]` f32 (out_hidden == text hidden, 1536),
//! ready to splice into the text residual stream in place of the image tokens.
//!
//! Weight naming (written by encode-knot.py glm_ocr branch; KnotWriter joins
//! `.`→`_`):
//!   vit_patch_embed_weight        [hidden, in_chans*temporal*p*p]
//!   vit_patch_embed_bias          [hidden]
//!   vit_blk_{i}_norm1_weight      [hidden]              RMSNorm
//!   vit_blk_{i}_norm2_weight      [hidden]              RMSNorm
//!   vit_blk_{i}_attn_qkv_weight   [3*hidden, hidden]    fused QKV
//!   vit_blk_{i}_attn_qkv_bias     [3*hidden]
//!   vit_blk_{i}_attn_q_norm_weight[head_dim]            per-head RMSNorm
//!   vit_blk_{i}_attn_k_norm_weight[head_dim]            per-head RMSNorm
//!   vit_blk_{i}_attn_proj_weight  [hidden, hidden]      (no bias on GLM proj)
//!   vit_blk_{i}_mlp_gate_weight   [inter, hidden] + bias[inter]
//!   vit_blk_{i}_mlp_up_weight     [inter, hidden] + bias[inter]
//!   vit_blk_{i}_mlp_down_weight   [hidden, inter] + bias[hidden]
//!   vit_post_layernorm_weight     [hidden]              RMSNorm
//!   vit_downsample_weight         [out_hidden, hidden, merge, merge]  (Conv2d)
//!   vit_downsample_bias           [out_hidden]
//!   vit_merger_proj_weight        [out_hidden, out_hidden]
//!   vit_merger_post_norm_weight   [out_hidden]          LayerNorm
//!   vit_merger_post_norm_bias     [out_hidden]
//!   vit_merger_gate_weight        [inter, out_hidden]
//!   vit_merger_up_weight          [inter, out_hidden]
//!   vit_merger_down_weight        [out_hidden, inter]

use std::sync::Arc;

use crate::loader::WeightBackend;
use crate::math::{
    accumulate_weighted, dot_product, gelu_inplace, layer_norm, mat_vec_f32, rms_norm, softmax,
};

// ─────────────────────────────────────────────────────────────────────────────
// Config
// ─────────────────────────────────────────────────────────────────────────────

#[derive(Debug, Clone)]
pub struct GlmOcrVitConfig {
    pub depth: usize,
    pub hidden_size: usize,
    pub num_heads: usize,
    pub intermediate_size: usize,
    pub patch_size: usize,
    pub temporal_patch_size: usize,
    pub in_chans: usize,
    pub spatial_merge_size: usize,
    pub out_hidden_size: usize,
    pub rms_norm_eps: f32,
    /// Merger SwiGLU inner dim. For GLM-OCR the merger `context_dim` equals the
    /// text `intermediate_size` (4608); gate/up are [merger_inter, out_hidden].
    pub merger_intermediate_size: usize,
}

impl Default for GlmOcrVitConfig {
    fn default() -> Self {
        // zai-org/GLM-OCR vision_config (verified 2026-05-24).
        Self {
            depth: 24,
            hidden_size: 1024,
            num_heads: 16,
            intermediate_size: 4096,
            patch_size: 14,
            temporal_patch_size: 2,
            in_chans: 3,
            spatial_merge_size: 2,
            out_hidden_size: 1536,
            rms_norm_eps: 1e-5,
            merger_intermediate_size: 4608,
        }
    }
}

impl GlmOcrVitConfig {
    #[inline]
    pub fn head_dim(&self) -> usize {
        self.hidden_size / self.num_heads
    }

    /// Flattened input dim of one Conv3d patch: in_chans * temporal * p * p.
    #[inline]
    pub fn patch_dim(&self) -> usize {
        self.in_chans * self.temporal_patch_size * self.patch_size * self.patch_size
    }

    #[inline]
    pub fn merge_unit(&self) -> usize {
        self.spatial_merge_size * self.spatial_merge_size
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Per-block tensor names (`.`→`_` joined keys)
// ─────────────────────────────────────────────────────────────────────────────

struct VitBlockNames {
    norm1: String,
    norm2: String,
    qkv_w: String,
    qkv_b: String,
    q_norm: String,
    k_norm: String,
    proj_w: String,
    gate_w: String,
    gate_b: String,
    up_w: String,
    up_b: String,
    down_w: String,
    down_b: String,
}

impl VitBlockNames {
    fn new(i: usize) -> Self {
        Self {
            norm1: format!("vit_blk_{i}_norm1_weight"),
            norm2: format!("vit_blk_{i}_norm2_weight"),
            qkv_w: format!("vit_blk_{i}_attn_qkv_weight"),
            qkv_b: format!("vit_blk_{i}_attn_qkv_bias"),
            q_norm: format!("vit_blk_{i}_attn_q_norm_weight"),
            k_norm: format!("vit_blk_{i}_attn_k_norm_weight"),
            proj_w: format!("vit_blk_{i}_attn_proj_weight"),
            gate_w: format!("vit_blk_{i}_mlp_gate_weight"),
            gate_b: format!("vit_blk_{i}_mlp_gate_bias"),
            up_w: format!("vit_blk_{i}_mlp_up_weight"),
            up_b: format!("vit_blk_{i}_mlp_up_bias"),
            down_w: format!("vit_blk_{i}_mlp_down_weight"),
            down_b: format!("vit_blk_{i}_mlp_down_bias"),
        }
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// ViT
// ─────────────────────────────────────────────────────────────────────────────

pub struct GlmOcrViT {
    pub config: GlmOcrVitConfig,
    backend: Arc<dyn WeightBackend>,
    blocks: Vec<VitBlockNames>,
}

impl GlmOcrViT {
    pub fn new(config: GlmOcrVitConfig, backend: Arc<dyn WeightBackend>) -> Self {
        let blocks = (0..config.depth).map(VitBlockNames::new).collect();
        Self {
            config,
            backend,
            blocks,
        }
    }

    /// Encode a preprocessed image (Qwen2-VL/GLM-OCR shared patch layout).
    ///
    /// `pixels`: flattened patch grid, shape `[n_patches, patch_dim]` row-major
    /// in raster patch order, where patch_dim = in_chans*temporal*patch*patch and
    /// each patch carries the temporal duplication. Produced by
    /// `preprocess-vl-image.py` (identical preprocessing to the Qwen2.5-VL path;
    /// GLM-OCR uses the same CLIP mean/std + patch/merge sizes).
    ///
    /// `grid_h`, `grid_w`: patch-grid dims, both multiples of `spatial_merge_size`.
    ///
    /// Returns `[n_merged_tokens, out_hidden]` where
    ///   n_merged_tokens = n_patches / merge_unit
    ///   out_hidden      = config.out_hidden_size (== text hidden, 1536).
    pub fn forward(
        &self,
        pixels: &[f32],
        grid_h: usize,
        grid_w: usize,
    ) -> Result<Vec<f32>, String> {
        let cfg = &self.config;
        let h = cfg.hidden_size;
        let n = grid_h * grid_w;
        let patch_dim = cfg.patch_dim();
        if pixels.len() != n * patch_dim {
            return Err(format!(
                "GlmOcrViT::forward: pixels len {} != n_patches*patch_dim {}*{}={}",
                pixels.len(),
                n,
                patch_dim,
                n * patch_dim
            ));
        }
        if !grid_h.is_multiple_of(cfg.spatial_merge_size) || !grid_w.is_multiple_of(cfg.spatial_merge_size) {
            return Err(format!(
                "GlmOcrViT::forward: grid {grid_h}x{grid_w} not divisible by merge {}",
                cfg.spatial_merge_size
            ));
        }

        // 1. Patch embed (Conv3d as matmul) + bias.
        let mut x = vec![0.0f32; n * h];
        {
            let wf = self.fetch_f32("vit_patch_embed_weight")?;
            let bf = self.fetch_f32("vit_patch_embed_bias")?;
            for t in 0..n {
                let inp = &pixels[t * patch_dim..(t + 1) * patch_dim];
                let dst = &mut x[t * h..(t + 1) * h];
                mat_vec_f32(dst, inp, &wf, h, patch_dim);
                for i in 0..h {
                    dst[i] += bf[i];
                }
            }
        }

        // 2. 2D-RoPE cos/sin tables per patch position (same convention as the
        //    Qwen2-VL ViT: head_dim split into a row-half and a col-half).
        let head_dim = cfg.head_dim();
        let (cos_tab, sin_tab) = self.build_rope_tables(grid_h, grid_w, head_dim);

        // 3. Transformer blocks (ALL full attention -- no windowing in GLM-OCR).
        for l in 0..cfg.depth {
            self.block(&mut x, l, n, &cos_tab, &sin_tab)?;
        }

        // 4. Final post_layernorm (RMSNorm).
        {
            let pln = self.fetch_f32("vit_post_layernorm_weight")?;
            let mut tmp = vec![0.0f32; h];
            for t in 0..n {
                rms_norm(&mut tmp, &x[t * h..(t + 1) * h], &pln, cfg.rms_norm_eps);
                x[t * h..(t + 1) * h].copy_from_slice(&tmp);
            }
        }

        // 5. Downsample (Conv2d 2×2 stride 2 over 2×2 patch blocks) → [n_merged, out_hidden].
        let downsampled = self.downsample(&x, grid_h, grid_w)?;

        // 6. Merger: proj → LayerNorm → GELU → SwiGLU.
        self.merger(&downsampled)
    }

    /// Build per-position cos/sin tables for 2D RoPE.
    /// Returns (cos, sin) each shaped [n_patches, head_dim].
    fn build_rope_tables(
        &self,
        grid_h: usize,
        grid_w: usize,
        head_dim: usize,
    ) -> (Vec<f32>, Vec<f32>) {
        // GLM-OCR vision RoPE layout (matches HF `GlmOcrVisionModel.rot_pos_emb` +
        // `apply_rotary_pos_emb_vision`, transformers 5.x). Per position the table is:
        //   rpe = cat(row_freqs[quarter], col_freqs[quarter])   (len = half)
        //   emb = cat(rpe, rpe)                                 (len = head_dim)
        // i.e. interleaved by AXIS-BLOCK, NOT axis-then-duplicate:
        //   [0..quarter)            = row freqs   (theta^-(2i/half), i in 0..quarter)
        //   [quarter..half)         = col freqs
        //   [half..half+quarter)    = row freqs   (the cat(rpe,rpe) repeat)
        //   [half+quarter..head_dim)= col freqs
        // The rotate_half application (`apply_rope`) then pairs dim i with dim
        // i+half, so the repeat puts each (row,col) freq's cos/sin in both halves.
        let n = grid_h * grid_w;
        let half = head_dim / 2; // dims [0,half) repeated into [half,head_dim)
        let quarter = half / 2; // rows fill [0,quarter), cols fill [quarter,half)
        let theta = 10000.0f32;
        let mut cos = vec![0.0f32; n * head_dim];
        let mut sin = vec![0.0f32; n * head_dim];
        // inv_freq over the half-axis: HF uses dim=head_dim/2 (=half) so the freq
        // exponent is 2i/half (== 2i/(head_dim/2)). `quarter` freqs per axis.
        let mut inv_freq = vec![0.0f32; quarter];
        for i in 0..quarter {
            inv_freq[i] = 1.0 / theta.powf((2 * i) as f32 / half as f32);
        }
        for r in 0..grid_h {
            for c in 0..grid_w {
                let p = r * grid_w + c;
                let base = p * head_dim;
                for i in 0..quarter {
                    // Row freqs at [0,quarter) and the cat-repeat at [half,half+quarter).
                    let ang = r as f32 * inv_freq[i];
                    let (s, co) = ang.sin_cos();
                    cos[base + i] = co;
                    cos[base + half + i] = co;
                    sin[base + i] = s;
                    sin[base + half + i] = s;
                    // Col freqs at [quarter,half) and the cat-repeat at [half+quarter,head_dim).
                    let ang_c = c as f32 * inv_freq[i];
                    let (s_c, co_c) = ang_c.sin_cos();
                    cos[base + quarter + i] = co_c;
                    cos[base + half + quarter + i] = co_c;
                    sin[base + quarter + i] = s_c;
                    sin[base + half + quarter + i] = s_c;
                }
            }
        }
        (cos, sin)
    }

    /// One transformer block: x += attn(rmsnorm1(x)); x += mlp(rmsnorm2(x)).
    fn block(
        &self,
        x: &mut [f32],
        l: usize,
        n: usize,
        cos_tab: &[f32],
        sin_tab: &[f32],
    ) -> Result<(), String> {
        let cfg = &self.config;
        let h = cfg.hidden_size;
        let inter = cfg.intermediate_size;
        let eps = cfg.rms_norm_eps;
        let bn = &self.blocks[l];
        let n_heads = cfg.num_heads;
        let head_dim = cfg.head_dim();

        // ── Attention ──
        let norm1 = self.fetch_f32(&bn.norm1)?;
        let mut xn = vec![0.0f32; n * h];
        for t in 0..n {
            rms_norm(
                &mut xn[t * h..(t + 1) * h],
                &x[t * h..(t + 1) * h],
                &norm1,
                eps,
            );
        }

        let qkv_w = self.fetch_f32(&bn.qkv_w)?;
        let qkv_b = self.fetch_f32(&bn.qkv_b)?;
        let q_norm_w = self.fetch_f32(&bn.q_norm)?;
        let k_norm_w = self.fetch_f32(&bn.k_norm)?;
        let qkv_dim = 3 * h;
        let mut q = vec![0.0f32; n * h];
        let mut k = vec![0.0f32; n * h];
        let mut v = vec![0.0f32; n * h];
        {
            let mut tmp = vec![0.0f32; qkv_dim];
            for t in 0..n {
                let inp = &xn[t * h..(t + 1) * h];
                mat_vec_f32(&mut tmp, inp, &qkv_w, qkv_dim, h);
                for i in 0..qkv_dim {
                    tmp[i] += qkv_b[i];
                }
                q[t * h..(t + 1) * h].copy_from_slice(&tmp[0..h]);
                k[t * h..(t + 1) * h].copy_from_slice(&tmp[h..2 * h]);
                v[t * h..(t + 1) * h].copy_from_slice(&tmp[2 * h..3 * h]);
            }
        }

        // Per-head q_norm / k_norm (RMSNorm over head_dim) -- applied BEFORE RoPE.
        apply_per_head_rms(&mut q, &q_norm_w, n, n_heads, head_dim, eps);
        apply_per_head_rms(&mut k, &k_norm_w, n, n_heads, head_dim, eps);

        // 2D RoPE on q, k.
        apply_rope(&mut q, cos_tab, sin_tab, n, n_heads, head_dim);
        apply_rope(&mut k, cos_tab, sin_tab, n, n_heads, head_dim);

        // Full attention over all patches.
        let scale = 1.0 / (head_dim as f32).sqrt();
        let mut attn_out = vec![0.0f32; n * h];
        let all: Vec<usize> = (0..n).collect();
        self.attend_set(&q, &k, &v, &mut attn_out, &all, n_heads, head_dim, h, scale);

        // output proj (NO bias on GLM-OCR vision proj) + residual add.
        let proj_w = self.fetch_f32(&bn.proj_w)?;
        {
            let mut o = vec![0.0f32; h];
            for t in 0..n {
                mat_vec_f32(&mut o, &attn_out[t * h..(t + 1) * h], &proj_w, h, h);
                for i in 0..h {
                    x[t * h + i] += o[i];
                }
            }
        }

        // ── SwiGLU MLP (with biases) ──
        let norm2 = self.fetch_f32(&bn.norm2)?;
        let gate_w = self.fetch_f32(&bn.gate_w)?;
        let gate_b = self.fetch_f32(&bn.gate_b)?;
        let up_w = self.fetch_f32(&bn.up_w)?;
        let up_b = self.fetch_f32(&bn.up_b)?;
        let down_w = self.fetch_f32(&bn.down_w)?;
        let down_b = self.fetch_f32(&bn.down_b)?;
        {
            let mut xn2 = vec![0.0f32; h];
            let mut gate = vec![0.0f32; inter];
            let mut up = vec![0.0f32; inter];
            let mut down = vec![0.0f32; h];
            for t in 0..n {
                rms_norm(&mut xn2, &x[t * h..(t + 1) * h], &norm2, eps);
                mat_vec_f32(&mut gate, &xn2, &gate_w, inter, h);
                mat_vec_f32(&mut up, &xn2, &up_w, inter, h);
                for i in 0..inter {
                    let g = gate[i] + gate_b[i];
                    let u = up[i] + up_b[i];
                    gate[i] = (g / (1.0 + (-g).exp())) * u; // SiLU(g)*u
                }
                mat_vec_f32(&mut down, &gate, &down_w, h, inter);
                for i in 0..h {
                    x[t * h + i] += down[i] + down_b[i];
                }
            }
        }

        Ok(())
    }

    /// Full multi-head attention over `members` token indices.
    #[allow(clippy::too_many_arguments)]
    fn attend_set(
        &self,
        q: &[f32],
        k: &[f32],
        v: &[f32],
        attn_out: &mut [f32],
        members: &[usize],
        n_heads: usize,
        head_dim: usize,
        h: usize,
        scale: f32,
    ) {
        let m = members.len();
        let mut scores = vec![0.0f32; m];
        for &t_out in members {
            for head in 0..n_heads {
                let q_off = t_out * h + head * head_dim;
                let q_head = &q[q_off..q_off + head_dim];
                for (si, &t_src) in members.iter().enumerate() {
                    let k_off = t_src * h + head * head_dim;
                    scores[si] = dot_product(q_head, &k[k_off..k_off + head_dim]) * scale;
                }
                softmax(&mut scores[..m]);
                let out_off = t_out * h + head * head_dim;
                let head_out = &mut attn_out[out_off..out_off + head_dim];
                head_out.fill(0.0);
                for (si, &t_src) in members.iter().enumerate() {
                    let v_off = t_src * h + head * head_dim;
                    accumulate_weighted(head_out, &v[v_off..v_off + head_dim], scores[si]);
                }
            }
        }
    }

    /// Downsample: Conv2d(in=hidden, out=out_hidden, k=merge, stride=merge) over
    /// the 2×2 patch blocks. Returns `[n_merged, out_hidden]`.
    ///
    /// The reference reshapes the post_layernorm sequence into
    /// `[-1, merge, merge, hidden]` then `permute(0,3,1,2)` and applies the conv.
    /// That reshape groups consecutive sequence positions into 2×2 blocks; with
    /// our raster patch order we gather each spatial 2×2 block directly. The conv
    /// weight is `[out, in_ch, kh, kw]`; flattened input order is (kh, kw, in_ch)
    /// matched against a re-laid weight indexed `[out][(kh*merge+kw)*hidden+ic]`.
    fn downsample(&self, x: &[f32], grid_h: usize, grid_w: usize) -> Result<Vec<f32>, String> {
        let cfg = &self.config;
        let h = cfg.hidden_size;
        let ms = cfg.spatial_merge_size;
        let out_hidden = cfg.out_hidden_size;

        let w_conv = self.fetch_f32("vit_downsample_weight")?; // [out, in_ch, kh, kw]
        let bias = self.fetch_f32("vit_downsample_bias")?; // [out]
        let merge_in = h * cfg.merge_unit();
        if w_conv.len() != out_hidden * merge_in {
            return Err(format!(
                "downsample weight len {} != out*in*kh*kw {}*{}*{}*{}={}",
                w_conv.len(),
                out_hidden,
                h,
                ms,
                ms,
                out_hidden * merge_in
            ));
        }

        // Re-lay the conv weight [out, in_ch, kh, kw] → [out, (kh*kw)*in_ch] so a
        // single mat_vec over the gathered block (ordered kh,kw,in_ch) computes
        // the convolution exactly. weight index: o*(in_ch*kh*kw) + ic*(kh*kw) +
        // kh*kw_size + kw  →  relaid[o*merge_in + (kh*ms+kw)*h + ic].
        let mut relaid = vec![0.0f32; out_hidden * merge_in];
        for o in 0..out_hidden {
            for ic in 0..h {
                for kh in 0..ms {
                    for kw in 0..ms {
                        let src = o * (h * ms * ms) + ic * (ms * ms) + kh * ms + kw;
                        let dst = o * merge_in + (kh * ms + kw) * h + ic;
                        relaid[dst] = w_conv[src];
                    }
                }
            }
        }

        let mh = grid_h / ms;
        let mw = grid_w / ms;
        let n_merged = mh * mw;
        let mut out = vec![0.0f32; n_merged * out_hidden];
        let mut block = vec![0.0f32; merge_in];
        for br in 0..mh {
            for bc in 0..mw {
                // Gather the 2×2 block in (kh, kw) order, each [hidden].
                let mut off = 0;
                for kh in 0..ms {
                    for kw in 0..ms {
                        let r = br * ms + kh;
                        let c = bc * ms + kw;
                        let p = r * grid_w + c;
                        block[off..off + h].copy_from_slice(&x[p * h..(p + 1) * h]);
                        off += h;
                    }
                }
                let mi = br * mw + bc;
                let dst = &mut out[mi * out_hidden..(mi + 1) * out_hidden];
                mat_vec_f32(dst, &block, &relaid, out_hidden, merge_in);
                for o in 0..out_hidden {
                    dst[o] += bias[o];
                }
            }
        }
        Ok(out)
    }

    /// Merger (GLM-OCR `Glm4vVisionPatchMerger`):
    ///   h = proj(x)                       (Linear, no bias, [out_hidden,out_hidden])
    ///   h = GELU(post_projection_norm(h)) (LayerNorm w/ bias, then GELU)
    ///   out = down(SiLU(gate(h)) * up(h)) (SwiGLU; gate/up/down no bias)
    /// Input/output both `[n_merged, out_hidden]`.
    fn merger(&self, x: &[f32]) -> Result<Vec<f32>, String> {
        let cfg = &self.config;
        let d = cfg.out_hidden_size;
        let inter = cfg.merger_intermediate_size;
        let eps = cfg.rms_norm_eps;
        let n = x.len() / d;

        let proj_w = self.fetch_f32("vit_merger_proj_weight")?; // [d, d]
        let pn_w = self.fetch_f32("vit_merger_post_norm_weight")?; // [d]
        let pn_b = self.fetch_f32("vit_merger_post_norm_bias")?; // [d]
        let gate_w = self.fetch_f32("vit_merger_gate_weight")?; // [inter, d]
        let up_w = self.fetch_f32("vit_merger_up_weight")?; // [inter, d]
        let down_w = self.fetch_f32("vit_merger_down_weight")?; // [d, inter]

        let mut out = vec![0.0f32; n * d];
        let mut proj = vec![0.0f32; d];
        let mut normed = vec![0.0f32; d];
        let mut gate = vec![0.0f32; inter];
        let mut up = vec![0.0f32; inter];
        for t in 0..n {
            let xi = &x[t * d..(t + 1) * d];
            mat_vec_f32(&mut proj, xi, &proj_w, d, d);
            // LayerNorm (mean+var, w/ bias) then GELU.
            layer_norm(&mut normed, &proj, &pn_w, &pn_b, eps);
            gelu_inplace(&mut normed);
            mat_vec_f32(&mut gate, &normed, &gate_w, inter, d);
            mat_vec_f32(&mut up, &normed, &up_w, inter, d);
            for i in 0..inter {
                let g = gate[i];
                gate[i] = (g / (1.0 + (-g).exp())) * up[i]; // SiLU(g)*up
            }
            mat_vec_f32(&mut out[t * d..(t + 1) * d], &gate, &down_w, d, inter);
        }
        Ok(out)
    }

    /// Fetch a vit tensor as f32, dequantizing per its declared qtype (F32 or
    /// Q8_0 -- the only two the encoder emits for vit_* tensors). Mirrors the
    /// Qwen2VL ViT loader.
    fn fetch_f32(&self, name: &str) -> Result<Vec<f32>, String> {
        let bytes = self
            .backend
            .fetch_tensor(name)
            .map_err(|e| format!("{name}: {e}"))?;
        let qtype = self
            .backend
            .tensor_info(name)
            .map(|ti| ti.tensor_type.to_ascii_lowercase())
            .unwrap_or_else(|| "f32".to_string());
        match qtype.as_str() {
            "q8_0" => {
                let n_elems = (bytes.len() / 34) * 32;
                let mut out = vec![0f32; n_elems];
                crate::math::dequantize_q8_0_row(&mut out, &bytes, 0, n_elems);
                Ok(out)
            }
            "f32" | "fp32" => Ok(bytes_to_f32(&bytes).to_vec()),
            other => Err(format!(
                "fetch_f32 {name}: unsupported vit qtype '{other}' (expected f32 or Q8_0)"
            )),
        }
    }
}

/// Per-head RMSNorm over `head_dim` applied in-place to a `[n, n_heads*head_dim]`
/// buffer. `w` is `[head_dim]` shared across heads (GLM/qwen3 q_norm/k_norm).
fn apply_per_head_rms(
    buf: &mut [f32],
    w: &[f32],
    n: usize,
    n_heads: usize,
    head_dim: usize,
    eps: f32,
) {
    let h = n_heads * head_dim;
    let mut tmp = vec![0.0f32; head_dim];
    for t in 0..n {
        for head in 0..n_heads {
            let base = t * h + head * head_dim;
            rms_norm(&mut tmp, &buf[base..base + head_dim], w, eps);
            buf[base..base + head_dim].copy_from_slice(&tmp);
        }
    }
}

/// Apply 2D RoPE in-place (rotate_half / half-split form), identical to the
/// Qwen2-VL ViT convention. cos/sin are [n, head_dim], shared across heads.
fn apply_rope(
    buf: &mut [f32],
    cos: &[f32],
    sin: &[f32],
    n: usize,
    n_heads: usize,
    head_dim: usize,
) {
    let h = n_heads * head_dim;
    let half = head_dim / 2;
    for t in 0..n {
        let cbase = t * head_dim;
        for head in 0..n_heads {
            let base = t * h + head * head_dim;
            for i in 0..half {
                let x0 = buf[base + i];
                let x1 = buf[base + i + half];
                let c0 = cos[cbase + i];
                let s0 = sin[cbase + i];
                let c1 = cos[cbase + i + half];
                let s1 = sin[cbase + i + half];
                buf[base + i] = x0 * c0 - x1 * s0;
                buf[base + i + half] = x1 * c1 + x0 * s1;
            }
        }
    }
}

#[inline]
fn bytes_to_f32(bytes: &[u8]) -> &[f32] {
    assert!(
        bytes.len().is_multiple_of(4),
        "bytes_to_f32: len {} not /4",
        bytes.len()
    );
    unsafe { std::slice::from_raw_parts(bytes.as_ptr() as *const f32, bytes.len() / 4) }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn zero_vit() -> GlmOcrViT {
        struct Z;
        impl WeightBackend for Z {
            fn fetch_tensor(&self, n: &str) -> Result<crate::loader::OwnedBytes, String> {
                Err(n.to_string())
            }
            fn has_tensor(&self, _: &str) -> bool {
                false
            }
            fn as_any(&self) -> &dyn std::any::Any {
                self
            }
        }
        GlmOcrViT::new(GlmOcrVitConfig::default(), Arc::new(Z))
    }

    #[test]
    fn config_dims() {
        let c = GlmOcrVitConfig::default();
        assert_eq!(c.head_dim(), 64); // 1024 / 16
        assert_eq!(c.patch_dim(), 3 * 2 * 14 * 14); // 1176
        assert_eq!(c.merge_unit(), 4);
        // downsample conv in-dim = hidden * merge^2 = 1024*4 = 4096.
        assert_eq!(c.hidden_size * c.merge_unit(), 4096);
        // merger out_hidden must equal text hidden (1536).
        assert_eq!(c.out_hidden_size, 1536);
    }

    #[test]
    fn rope_tables_origin_identity() {
        let c = GlmOcrVitConfig::default();
        let vit = zero_vit();
        let (cos, sin) = vit.build_rope_tables(4, 6, c.head_dim());
        assert_eq!(cos.len(), 4 * 6 * c.head_dim());
        assert_eq!(sin.len(), 4 * 6 * c.head_dim());
        // position (0,0) → cos=1, sin=0 for every dim.
        for i in 0..c.head_dim() {
            assert!((cos[i] - 1.0).abs() < 1e-6);
            assert!(sin[i].abs() < 1e-6);
        }
    }

    #[test]
    fn per_head_rms_shape_preserved() {
        let n = 3usize;
        let n_heads = 2usize;
        let head_dim = 4usize;
        let mut buf = vec![1.0f32; n * n_heads * head_dim];
        let w = vec![1.0f32; head_dim];
        apply_per_head_rms(&mut buf, &w, n, n_heads, head_dim, 1e-5);
        // RMSNorm of an all-ones head with unit weight ≈ 1.0 per element.
        for &x in &buf {
            assert!((x - 1.0).abs() < 1e-3, "got {x}");
        }
    }
}
